    },
    "core": {
      "rating": "red",
      "evidence": [
        "normalized.upf.gtp_indatapktn3upf_per_ue is near zero",
        "normalized.upf.gtp_outdatapktn3upf_per_ue is near zero"
      ],
      "note": "The user plane is completely inactive, indicating a severe fault in the core data path (UPF) or a complete lack of call setup to activate it."
