    "ims": {
      "rating": "red",
      "evidence": [
        "derived.pcscf_sip_error_ratio spiked from 0.0 to 0.25",
        "normalized.pcscf.dialogs_per_ue dropped to 0.0",
        "pcscf.httpclient:connfail is high (44)"
      ],
      "note": "The P-CSCF is rejecting SIP requests and failing to make HTTP connections, indicating a critical failure in the IMS call setup flow, likely when communicating with the PCF."
